# -*- coding: utf-8 -*-
GLOBAL = [
    {"hero":True,"sub":"Conflicts & Security","h3":"US hits Iran again after Strait of Hormuz ship attack","summary":"American forces struck Iranian military sites after a drone hit a cargo vessel, straining the fragile ceasefire.","body":["US Central Command said American aircraft struck Iranian missile and drone storage sites along with coastal radar installations on Friday, calling it a powerful response to an attack a day earlier on the commercial ship Ever Lovely in the Strait of Hormuz. Washington said Iran fired at least four one-way attack drones at vessels passing through the strait.","President Trump accused Tehran of a foolish violation of the Islamabad Memorandum signed in mid-June. Iran's foreign ministry strongly condemned the strikes as an explicit breach of the understanding, raising fears the ceasefire could unravel."],"sources":[("Al Jazeera","https://www.aljazeera.com/news/liveblog/2026/6/27/iran-war-live-us-strikes-iran-after-fire-on-vessel-in-strait-of-hormuz"),("Bloomberg","https://www.bloomberg.com/news/articles/2026-06-26/us-strikes-iran-in-response-to-ship-attack-in-strait-of-hormuz")]},
    {"sub":"Conflicts & Security","h3":"Bahrain condemns Iranian drone attack on its territory","summary":"Manama reported minor damage and no casualties after drones struck, vowing to defend its sovereignty.","body":["Bahrain's foreign ministry issued its strongest condemnation after a number of Iranian drones hit its territory on Saturday, calling it a blatant violation of sovereignty. State media said the strikes caused minor structural damage to several buildings and infrastructure but no casualties.","Iran said it had targeted sites linked to US forces in the region without specifying locations. Egypt, Kuwait and the GCC secretary general also condemned the attack, warning that targeting civilian facilities undermines efforts to contain the crisis."],"sources":[("Arab News","https://www.arabnews.com/node/2648756/middle-east"),("NPR","https://www.npr.org/2026/06/27/nx-s1-5872954/us-strikes-iran")]},
    {"sub":"Conflicts & Security","h3":"Ukraine launches one of its biggest drone assaults of the war","summary":"Kyiv hit a dozen Russian regions and Crimea, with Moscow claiming it downed 660 drones.","body":["Ukraine carried out one of its largest drone bombardments since the start of Russia's full-scale invasion, striking a dozen Russian regions, occupied Crimea and surrounding waters. Russia's defence ministry said its air defences intercepted 660 drones, surpassing the previous high of 556 in May.","The attack followed President Zelenskyy's announcement of a 40-day influence operation aimed at compelling Russia to end the war after a year of stalled US peace efforts. Russian strikes overnight injured people in Zaporizhzhia and Sumy, including several children."],"sources":[("NPR","https://www.npr.org/2026/06/26/nx-s1-5872256/russia-ukraine-war-drone-strikes"),("Al Jazeera","https://www.aljazeera.com/news/2026/6/25/as-ukraine-seizes-first-chance-to-win-war-horrors-come-home-to-russia")]},
    {"sub":"Conflicts & Security","h3":"Netanyahu to send delegation to Washington over Iran deal","summary":"Israel was excluded from the US-Iran agreement and wants to press its security concerns in person.","body":["Prime Minister Benjamin Netanyahu said Israel will send a delegation to Washington to clarify its interests on the nuclear provisions of any US-Iran agreement. He said Israel was not a party to the deal but has interests it intends to make known.","Netanyahu did not give a timeline or name officials taking part. He also reiterated that Israel will maintain its security zone in southern Lebanon as regional tensions climb."],"sources":[("Times of Israel","https://www.timesofisrael.com/liveblog_entry/netanyahu-says-he-plans-to-send-delegation-to-dc-to-express-israels-concerns-over-us-iran-deal-it-was-excluded-from/")]},
    {"sub":"Conflicts & Security","h3":"Gaza ceasefire frays as deaths mount past 1,000","summary":"Palestinian authorities say Israeli operations have killed more than 1,000 people since the October truce.","body":["Israeli operations in Gaza have killed over 1,000 Palestinians since the ceasefire reached last October, Palestinian authorities said, with thousands more injured. Second-phase negotiations remain stalled over Hamas disarmament and repeated strikes.","Israel now controls roughly 60 percent of Gaza, up from about half when the truce was signed, and Netanyahu has said it plans to take 70 percent. Aid deliveries remain far below agreed levels, with only about a third of allocated trucks entering the territory."],"sources":[("NPR","https://www.npr.org/2026/06/18/g-s1-128734/over-1-000-people-killed-during-gaza-ceasefire-palestinian-authorities-say"),("PBS NewsHour","https://www.pbs.org/newshour/world/there-are-supposed-to-be-ceasefires-across-the-middle-east-the-fighting-is-worsening")]},
    {"sub":"Conflicts & Security","h3":"Russia and Ukraine swap 160 prisoners each","summary":"Both sides brought home captured soldiers in a prisoner exchange on Friday.","body":["Russia and Ukraine exchanged prisoners of war, with 160 returning to each side on Friday. The swap was one of the few areas of continued cooperation as fighting and aerial bombardments intensified.","The exchange came amid one of the heaviest Ukrainian drone campaigns of the war and renewed Russian strikes on Ukrainian cities."],"sources":[("NPR","https://www.npr.org/2026/06/26/nx-s1-5872256/russia-ukraine-war-drone-strikes")]},
    {"sub":"Diplomacy & Trade","h3":"Trump threatens 100% tariff on Europe over digital taxes","summary":"The president vowed sweeping duties on the EU as a dispute over digital services taxes escalated.","body":["Trump said on June 26 that he would impose a 100 percent tariff on Europe over its digital services taxes, intensifying transatlantic trade tensions. The threat came just days after the EU gave final approval to a US trade deal ahead of a Trump deadline.","The move followed a June 11 agreement with China that left a combined 30 percent in fentanyl and reciprocal tariffs in place while pausing higher rates for 60 days. It signals continued volatility in US trade policy heading into the summer."],"sources":[("Bloomberg","https://www.bloomberg.com/latest/trump-tariffs"),("Atlantic Council","https://www.atlanticcouncil.org/programs/geoeconomics-center/trump-tariff-tracker/")]},
    {"sub":"Diplomacy & Trade","h3":"NATO allies head to Ankara with defense spending in focus","summary":"European members are outpacing expectations on military budgets ahead of the July summit in Turkey.","body":["New NATO figures show European allies exceeding forecasts on defense spending ahead of the Ankara summit, a welcome signal amid transatlantic strain. Secretary General Mark Rutte said the gathering will further demonstrate Europe's commitment to a stronger military.","Allies agreed at last year's Hague summit to invest 5 percent of GDP on defense and security by 2035. European allies and Canada raised spending 20 percent in 2025, and Norway became the first European ally to surpass US defense spending per capita."],"sources":[("Washington Times","https://www.washingtontimes.com/news/2026/jun/25/bigger-defense-spending-top-agenda-upcoming-nato-summit-turkey/"),("Atlantic Council","https://www.atlanticcouncil.org/commentary/trackers-and-data-visualizations/nato-defense-spending-tracker/")]},
    {"sub":"Diplomacy & Trade","h3":"EU leaders back Ukraine and budget at Brussels summit","summary":"The European Council adopted conclusions on Ukraine, the Middle East and the next long-term budget.","body":["EU leaders met in Brussels for a two-day summit that advanced unity on the next long-term budget, fair global competition and continued support for Ukraine. They adopted conclusions covering the Middle East, defense, migration, enlargement and reforms.","Leaders exchanged views with President Zelenskyy on developments on the ground and welcomed progress in Moldova's accession talks, backing a planned EU-Moldova summit. The EU also hosted the 10th Ministerial on Climate Action during the week."],"sources":[("European Council","https://www.consilium.europa.eu/en/meetings/european-council/2026/06/18-19/")]},
    {"sub":"Diplomacy & Trade","h3":"EU and South Korea sign digital trade pact","summary":"Brussels and Seoul deepened economic and security ties at their first summit in eight years.","body":["President Lee Jae-myung met European Council President Antonio Costa and Commission President Ursula von der Leyen in Brussels, becoming the first South Korean leader to meet EU chiefs in eight years. The sides signed a new Digital Trade Agreement.","Leaders endorsed a High-Level Economic Dialogue and a competitiveness partnership to boost economic resilience. The summit capped Lee's broader European tour that also took in Italy and the Vatican before the G7."],"sources":[("EEAS","https://www.eeas.europa.eu/delegations/south-korea/joint-statement-following-11th-european-union-%E2%80%93-republic-korea-summit_en"),("Korea Herald","https://www.koreaherald.com/article/10775859")]},
    {"sub":"Diplomacy & Trade","h3":"US population decline could accelerate after deportation ruling","summary":"A Supreme Court decision backing mass deportations adds to demographic pressures, analysts say.","body":["The US population was already aging and tilting toward decline before the Supreme Court confirmed the administration's power to deport hundreds of thousands of migrants. Analysts said the ruling could accelerate that decline.","The decision clears the way for large-scale removals at a time when immigration has been a key driver of population growth."],"sources":[("Al Jazeera","https://www.aljazeera.com/")]},
    {"sub":"Humanitarian & Climate","h3":"Venezuela earthquakes kill more than 900","summary":"Back-to-back quakes near Caracas flattened buildings, with tens of thousands reported missing.","body":["A magnitude 7.2 quake struck near San Felipe west of Caracas on Wednesday evening, followed almost immediately by a magnitude 7.5 quake near Yumare, the country's most powerful in more than a century. Officials said at least 920 people were killed, over 4,500 injured and more than 50,000 reported missing.","Many residents were left with nowhere to go after homes collapsed in La Guaira, Caracas and surrounding areas. International rescue teams, including one from the Netherlands, were deployed to assist the search effort."],"sources":[("CNN","https://www.cnn.com/2026/06/26/world/live-news/venezuela-earthquake-hnk"),("Al Jazeera","https://www.aljazeera.com/news/2026/6/25/venezuela-struck-by-back-to-back-earthquakes-high-casualties-feared")]},
    {"sub":"Humanitarian & Climate","h3":"Europe swelters under most severe heatwave on record","summary":"Scientists call the late-June heat the region's worst ever, with deaths and broken records across the continent.","body":["A widespread late-June heatwave shattered temperature records across Europe, which the World Weather Attribution network described as the most severe ever recorded. Denmark's all-time record briefly fell at 36.6C and at least 18 people died in France, including children and elderly people.","Researchers said both daytime highs and nighttime temperatures would have been virtually impossible 50 years ago, attributing the intensity to human-driven climate change. The heat strained health systems, transport, energy and water supplies from Portugal to the Balkans."],"sources":[("CNN","https://www.cnn.com/2026/06/26/climate/european-heat-wave-impossible-global-warming"),("WMO","https://wmo.int/media/news/records-fall-extreme-heat-grips-europe")]},
    {"sub":"Humanitarian & Climate","h3":"Sudan famine risk grows as civil war enters fifth year","summary":"Nearly 20 million people face acute hunger and 14 areas are at risk of famine amid escalating violence.","body":["About 19.5 million people in Sudan face high levels of acute food insecurity, with roughly 135,000 in catastrophic conditions and 14 areas across Greater Darfur and Kordofan at risk of famine. Sudan remains the world's largest internal displacement crisis with more than 9 million people displaced.","Dozens of civilians were killed over Eid al-Adha as fighting escalated, and RSF drone strikes hit El Obeid after a power transformer attack caused a blackout. A suspected cholera outbreak in West Kordofan has caused more than 300 cases and 77 deaths, while only 22 percent of the humanitarian appeal is funded."],"sources":[("Security Council Report","https://www.securitycouncilreport.org/monthly-forecast/2026-06/sudan-39.php"),("Doctors Without Borders","https://www.doctorswithoutborders.org/latest/sudan-crisis-response")]},
    {"sub":"Humanitarian & Climate","h3":"UN urges parties to consolidate fragile Gaza ceasefire","summary":"The Security Council heard calls to halt escalating West Bank violence and settlement activity.","body":["The UN Deputy Special Coordinator told a Security Council open debate that the parties must consolidate the Gaza ceasefire and halt escalating violence and settlement activity in the West Bank. The appeal came amid mounting concern over the truce's durability.","Diplomats warned that continued military operations and the slow pace of aid deliveries are undermining the agreement reached last October."],"sources":[("UN Press","https://press.un.org/en/2026/sc16284.doc.htm")]},
    {"sub":"Humanitarian & Climate","h3":"Cape Verde becomes smallest nation to reach World Cup last 32","summary":"The Atlantic islands advanced undefeated, sparking celebrations among diaspora communities.","body":["Cape Verde became the smallest country by population to reach the knockout stage of a men's World Cup after a goalless draw with Saudi Arabia in Houston, finishing second in their group with draws against Spain, Uruguay and Saudi Arabia. With about 525,000 people, the nation is smaller than any US state.","They are the first debutants to reach the knockouts since Slovakia in 2010 and the first newcomers to go unbeaten in the group stage since Senegal in 2002, prompting jubilant celebrations including among Cape Verdean communities in Rotterdam."],"sources":[("ESPN","https://www.espn.com/soccer/story/_/id/49192570/cape-verde-w2026-world-cup-knockout-stage-smallest-nation")]},
]

NETHERLANDS = [
    {"hero":True,"sub":"Politics & Policy","h3":"Cabinet unveils 250 million euro nitrogen plan, farmers furious","summary":"The Jetten government wants to halve nitrogen emissions by 2035, drawing immediate protest from farmers.","body":["The cabinet set out a 250 million euro package aimed at cutting nitrogen emissions by 50 percent by 2035, with mandatory reductions for farmers, industry and transport. Under the proposals farmers would need to cut emissions by 42 to 46 percent while industry and mobility face 50 percent cuts.","Dutch farmers immediately denounced the sweeping cuts, and officials are reportedly bracing for another summer of protests. Public dissatisfaction is already high and authorities warn it could escalate quickly."],"sources":[("NL Times","https://nltimes.nl/2026/06/26/cabinet-sets-eu250-million-package-reduce-nitrogen-emissions-50-2035"),("NL Times","https://nltimes.nl/2026/06/27/dutch-farmers-denounce-sweeping-nitrogen-emissions-cuts")]},
    {"sub":"Politics & Policy","h3":"Dutch government pushes EU ban on plastic-based chewing gum","summary":"The Hague wants Brussels to outlaw plastic gum as part of a wider fight against litter.","body":["The Dutch government is pushing for an EU-wide ban on plastic-based chewing gum amid a growing litter crisis. Officials argue the gum, which contains synthetic polymers, contributes to persistent street and waterway pollution.","The proposal would require manufacturers to shift to biodegradable alternatives. It forms part of a broader Dutch effort to reduce single-use plastics across the bloc."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/dutch-government-pushes-eu-ban-plastic-based-chewing-gum-amid-litter-crisis")]},
    {"sub":"Politics & Policy","h3":"Dutch rescue team arrives in Venezuela as toll passes 900","summary":"A Netherlands search and rescue team joined relief efforts after the deadly earthquakes near Caracas.","body":["A Dutch rescue team arrived in Venezuela to support search and recovery operations after two powerful earthquakes killed more than 900 people. The team was deployed as international aid poured into the disaster zone.","The quakes flattened buildings in Caracas, La Guaira and surrounding areas, leaving thousands injured and tens of thousands reported missing."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/video-dutch-rescue-team-arrives-venezuela-earthquake-death-toll-reaches-920")]},
    {"sub":"Economy & Housing","h3":"Energy firms shift to softer debt collection to help customers","summary":"Dutch energy companies are adopting customer-friendly approaches to help clients struggling with bills.","body":["Energy companies in the Netherlands are moving toward more customer-friendly debt collection methods to help clients keep up with payments. The shift aims to prevent households from falling into deeper financial trouble.","The change comes as many households continue to feel pressure from elevated living costs. Providers say earlier and gentler contact with customers can reduce arrears."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/energy-companies-shift-customer-friendly-debt-collection-help-clients-pay-bills")]},
    {"sub":"Economy & Housing","h3":"Most Dutch finance chiefs turn gloomier on the economy","summary":"A majority of CFOs say they are less optimistic about the economic outlook.","body":["A new survey found that 52 percent of Dutch chief financial officers are less optimistic about the economic outlook than before. The shift reflects growing caution among corporate leaders amid global trade tensions and slowing growth.","Economists expect Dutch growth to ease to around 1.3 percent in 2026 and 2027, down from 1.7 percent in 2025, with unemployment edging higher."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/52-dutch-chief-financial-officers-less-optimistic-economic-outlook")]},
    {"sub":"Economy & Housing","h3":"Nationwide Rijkswaterstaat outage disrupts bridges and tunnels","summary":"A technical failure hit traffic systems controlling bridges and tunnels across the country.","body":["A nationwide Rijkswaterstaat outage disrupted bridges, tunnels and traffic management systems across the Netherlands. The failure affected infrastructure that relies on centralized control.","Authorities worked to restore systems as drivers and shipping faced delays. The incident raised fresh questions about the resilience of national transport infrastructure."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/nationwide-rijkswaterstaat-outage-disrupts-bridges-tunnels-traffic-systems")]},
    {"sub":"Society & Culture","h3":"Netherlands records first regional super heatwave since 2020","summary":"A persistent heatwave pushed temperatures past 30C in Ell, marking the first regional super heatwave in years.","body":["The Netherlands recorded its first regional super heatwave since 2020 as the southern village of Ell hit 30.4C, capping a stretch of extreme heat. The KNMI kept a Code Red warning in place across several southern provinces.","Earlier in the week Eindhoven broke the Dutch June temperature record at 38.2C, and Terschelling set a Wadden Islands record of 33.6C. Events were canceled in Rotterdam and a woman gave birth on the N44 highway amid the heat."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/netherlands-records-first-regional-super-heatwave-since-2020-ell-hits-304-degc"),("DutchNews.nl","https://www.dutchnews.nl/2026/06/dutch-weather-service-issues-first-ever-code-red-for-heat/")]},
    {"sub":"Society & Culture","h3":"Severe thunderstorms hit south after record heat","summary":"KNMI upgraded its warning to Code Orange as large hail and strong gusts swept in.","body":["The KNMI upgraded its severe thunderstorm warning to Code Orange and did not rule out a tornado risk as storms developed across the south. Hailstones of 2 to 5 centimeters and wind gusts of up to 100 km/h were forecast.","Pingpong-sized hail struck Koudekerke and Dishoek, with lightning damaging homes and cars. The storms followed the country's most intense June heat on record."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/severe-thunderstorm-warning-upgraded-netherlands-tornado-risk-ruled"),("NL Times","https://nltimes.nl/2026/06/27/pingpong-sized-hail-strikes-koudekerke-dishoek-lightning-damages-homes-cars")]},
    {"sub":"Society & Culture","h3":"Rotterdam erupts in celebration after Cape Verde draw","summary":"The city saw fierce celebrations as Cape Verde reached the World Cup knockouts.","body":["Rotterdam saw another round of fierce celebrations after Cape Verde drew with Saudi Arabia to reach the World Cup knockout stage. The city is home to a large Cape Verdean community that took to the streets.","The Atlantic islands became the smallest nation by population ever to reach the last 32 of a men's World Cup, fueling pride among the diaspora."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/another-round-fierce-rotterdam-celebrations-cape-verde-draw-saudi-arabia")]},
    {"sub":"Society & Culture","h3":"One in three workers fear AI will make jobs mentally harder","summary":"A new survey finds many Dutch workers expect artificial intelligence to increase mental strain.","body":["About one-third of workers in the Netherlands expect artificial intelligence to make their jobs mentally harder rather than easier, according to a new survey. Concerns center on increased complexity and pressure rather than relief from routine tasks.","The findings add to a wider debate about how AI is reshaping Dutch workplaces and employee wellbeing."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/one-third-workers-expect-ai-make-jobs-mentally-harder")]},
    {"sub":"Society & Culture","h3":"Health officials warn over falling STI checks","summary":"Gonorrhoea and syphilis cases are rising as fewer people get tested.","body":["Dutch health officials warned that falling rates of STI testing are coinciding with a rise in gonorrhoea and syphilis cases. They urged more people to get checked to curb the spread.","The warning highlights gaps in sexual health screening despite growing case numbers."],"sources":[("NL Times","https://nltimes.nl/2026/06/27/warning-falling-sti-checks-gonorrhoea-syphilis-cases-grow")]},
    {"sub":"Society & Culture","h3":"Oranje fans set off on 1,800km journey to Mexico","summary":"Dutch supporters began a long road trip to follow the national team's World Cup campaign.","body":["Dutch football fans set off on an 1,800km journey to Mexico to follow the Oranje, traveling in vintage and modern double-decker Oranje buses after the team's group stage match in Kansas City. The convoy is bound for the Netherlands' clash against Morocco.","The trek underscores the scale of the Dutch traveling support at the expanded World Cup across North America."],"sources":[("NL Times","https://nltimes.nl/2026/06/26/oranje-supporters-bus-begins-1800km-journey-mexico-morocco-match")]},
]

MOOD = {"h3":"Sfeer vandaag","p":"Een snikhete week loopt uit op onweer. Na de eerste regionale superhittegolf sinds 2020, met records in Eindhoven en op Terschelling, sloeg het weer om met code oranje, ping-pongbal-grote hagel en zware windstoten in het zuiden. De stemming is dubbel: opluchting dat de hitte breekt, maar ook zorgen over de schade en de nieuwe stikstofplannen die boeren op de kast jagen. In Rotterdam overheerst feeststemming na het WK-succes van Kaapverdie."}
